// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 1000000

// Structure to represent an edge
typedef struct Edge {
    int v;
    struct Edge* next;
} Edge;

// Function to add an edge to the adjacency list
void addEdge(Edge** adj, int u, int v) {
    Edge* newEdge = (Edge*) malloc(sizeof(Edge));
    newEdge->v = v;
    newEdge->next = adj[u];
    adj[u] = newEdge;
}

// Function to perform DFS
int dfs(Edge** adj, int u, int* visited, int* count) {
    visited[u] = 1;
    (*count)++;
    for (Edge* temp = adj[u]; temp; temp = temp->next) {
        if (!visited[temp->v]) {
            dfs(adj, temp->v, visited, count);
        }
    }
}

// Function to count the number of valid pairs
int countValidPairs(Edge** adj, int N) {
    int count = 0;
    for (int i = 0; i < N; i++) {
        for (int j = i; j < N; j++) {
            int* visited = (int*) calloc(N, sizeof(int));
            int* countArr = (int*) malloc(sizeof(int));
            *countArr = 0;
            dfs(adj, i, visited, countArr);
            if (*countArr == j - i + 1) {
                count++;
            }
            free(visited);
            free(countArr);
        }
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        Edge** adj = (Edge**) malloc(N * sizeof(Edge*));
        for (int i = 0; i < N; i++) {
            adj[i] = NULL;
        }
        for (int i = 0; i < N - 1; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            u--;
            v--;
            addEdge(adj, u, v);
            addEdge(adj, v, u);
        }
        printf("%d\n", countValidPairs(adj, N));
        for (int i = 0; i < N; i++) {
            Edge* temp = adj[i];
            while (temp) {
                Edge* next = temp->next;
                free(temp);
                temp = next;
            }
        }
        free(adj);
    }
    return 0;
}

