import java.util.Scanner;
import java.util.ArrayList;

public class Main {
    // Function to count the number of valid pairs
    public static int countValidPairs(ArrayList<ArrayList<Integer>> adj, int N) {
        int count = 0;
        for (int i = 0; i < N; i++) {
            for (int j = i; j < N; j++) {
                boolean[] visited = new boolean[N];
                int[] countArr = new int[1];
                dfs(adj, i, visited, countArr);
                if (countArr[0] == j - i + 1) {
                    count++;
                }
            }
        }
        return count;
    }

    // Function to perform DFS
    public static void dfs(ArrayList<ArrayList<Integer>> adj, int u, boolean[] visited, int[] countArr) {
        visited[u] = true;
        countArr[0]++;
        for (int v : adj.get(u)) {
            if (!visited[v]) {
                dfs(adj, v, visited, countArr);
            }
        }
    }

    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        int T = sc.nextInt();
        while (T-- > 0) {
            int N = sc.nextInt();
            ArrayList<ArrayList<Integer>> adj = new ArrayList<>();
            for (int i = 0; i < N; i++) {
                adj.add(new ArrayList<>());
            }
            for (int i = 0; i < N - 1; i++) {
                int u = sc.nextInt() - 1;
                int v = sc.nextInt() - 1;
                adj.get(u).add(v);
                adj.get(v).add(u);
            }
            System.out.println(countValidPairs(adj, N));
        }
    }
}

